<final_file_content path="/Users/gangjeonghyeon/Desktop/clinetest/calculator.html">
<!doctype html>
<html lang="ko">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>계산기</title>
    <style>
      * {
        margin: 0;
        padding: 0;
        box-sizing: border-box;
      }

      body {
        display: flex;
        justify-content: center;
        align-items: center;
        min-height: 100vh;
        background: linear-gradient(135deg, #1a1a2e, #16213e, #0f3460);
        font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
      }

      .calculator {
        background: rgba(255, 255, 255, 0.05);
        backdrop-filter: blur(20px);
        border-radius: 20px;
        padding: 24px;
        box-shadow: 0 25px 60px rgba(0, 0, 0, 0.5);
        border: 1px solid rgba(255, 255, 255, 0.1);
        width: 340px;
      }

      .display {
        background: rgba(0, 0, 0, 0.3);
        border-radius: 14px;
        padding: 20px 24px;
        margin-bottom: 20px;
        text-align: right;
        border: 1px solid rgba(255, 255, 255, 0.05);
      }

      .display .expression {
        color: rgba(255, 255, 255, 0.5);
        font-size: 16px;
        min-height: 24px;
        word-break: break-all;
      }

      .display .result {
        color: #fff;
        font-size: 40px;
        font-weight: 300;
        margin-top: 8px;
        overflow: hidden;
        text-overflow: ellipsis;
      }

      .buttons {
        display: grid;
        grid-template-columns: repeat(4, 1fr);
        gap: 12px;
      }

      button {
        padding: 18px;
        font-size: 20px;
        border: none;
        border-radius: 14px;
        cursor: pointer;
        transition: all 0.2s ease;
        font-weight: 500;
      }

      button:active {
        transform: scale(0.95);
      }

      .btn-number {
        background: rgba(255, 255, 255, 0.08);
        color: #fff;
      }

      .btn-number:hover {
        background: rgba(255, 255, 255, 0.15);
      }

      .btn-operator {
        background: rgba(99, 102, 241, 0.4);
        color: #a5b4fc;
      }

      .btn-operator:hover {
        background: rgba(99, 102, 241, 0.6);
      }

      .btn-function {
        background: rgba(255, 255, 255, 0.04);
        color: rgba(255, 255, 255, 0.7);
      }

      .btn-function:hover {
        background: rgba(255, 255, 255, 0.1);
      }

      .btn-equals {
        background: linear-gradient(135deg, #6366f1, #8b5cf6);
        color: #fff;
        grid-column: span 1;
      }

      .btn-equals:hover {
        background: linear-gradient(135deg, #7c7ff7, #9d78f8);
      }

      .btn-clear {
        background: rgba(239, 68, 68, 0.3);
        color: #fca5a5;
      }

      .btn-clear:hover {
        background: rgba(239, 68, 68, 0.5);
      }

      .btn-zero {
        grid-column: span 2;
      }
    </style>
  </head>
  <body>
    <div class="calculator">
      <div class="display">
        <div class="expression" id="expression"></div>
        <div class="result" id="result">0</div>
      </div>
      <div class="buttons">
        <button class="btn-clear" onclick="clearAll()">AC</button>
        <button class="btn-function" onclick="toggleSign()">+/−</button>
        <button class="btn-function" onclick="percent()">%</button>
        <button class="btn-operator" onclick="setOperator('÷')">÷</button>

        <button class="btn-number" onclick="appendNumber('7')">7</button>
        <button class="btn-number" onclick="appendNumber('8')">8</button>
        <button class="btn-number" onclick="appendNumber('9')">9</button>
        <button class="btn-operator" onclick="setOperator('×')">×</button>

        <button class="btn-number" onclick="appendNumber('4')">4</button>
        <button class="btn-number" onclick="appendNumber('5')">5</button>
        <button class="btn-number" onclick="appendNumber('6')">6</button>
        <button class="btn-operator" onclick="setOperator('−')">−</button>

        <button class="btn-number" onclick="appendNumber('1')">1</button>
        <button class="btn-number" onclick="appendNumber('2')">2</button>
        <button class="btn-number" onclick="appendNumber('3')">3</button>
        <button class="btn-operator" onclick="setOperator('+')">+</button>

        <button class="btn-number btn-zero" onclick="appendNumber('0')">
          0
        </button>
        <button class="btn-number" onclick="appendDot()">.</button>
        <button class="btn-equals" onclick="calculate()">=</button>
      </div>
    </div>

    <script>
      let currentInput = "0";
      let previousInput = "";
      let operator = null;
      let shouldResetInput = false;

      const expressionEl = document.getElementById("expression");
      const resultEl = document.getElementById("result");

      function updateDisplay() {
        resultEl.textContent = currentInput;
        // 글자 크기 자동 조절
        if (currentInput.length > 12) {
          resultEl.style.fontSize = "24px";
        } else if (currentInput.length > 8) {
          resultEl.style.fontSize = "32px";
        } else {
          resultEl.style.fontSize = "40px";
        }
      }

      function appendNumber(num) {
        if (shouldResetInput) {
          currentInput = "0";
          shouldResetInput = false;
        }
        if (currentInput === "0" && num !== ".") {
          currentInput = num;
        } else if (currentInput.length < 15) {
          currentInput += num;
        }
        updateDisplay();
      }

      function appendDot() {
        if (shouldResetInput) {
          currentInput = "0";
          shouldResetInput = false;
        }
        if (!currentInput.includes(".")) {
          currentInput += ".";
        }
        updateDisplay();
      }

      function setOperator(op) {
        if (operator && !shouldResetInput) {
          calculate();
        }
        previousInput = currentInput;
        operator = op;
        shouldResetInput = true;
        expressionEl.textContent = `${formatNumber(previousInput)} ${operator}`;
      }

      function calculate() {
        if (!operator || (shouldResetInput && !previousInput)) return;

        const prev = parseFloat(previousInput);
        const curr = parseFloat(currentInput);
        let result;

        switch (operator) {
          case "+":
            result = prev + curr;
            break;
          case "−":
            result = prev - curr;
            break;
          case "×":
            result = prev * curr;
            break;
          case "÷":
            if (curr === 0) {
              currentInput = "오류";
              operator = null;
              previousInput = "";
              expressionEl.textContent = "";
              updateDisplay();
              shouldResetInput = true;
              return;
            }
            result = prev / curr;
            break;
          default:
            return;
        }

        // 부동소수점 오차 보정
        result = parseFloat(result.toPrecision(12));

        expressionEl.textContent = `${formatNumber(previousInput)} ${operator} ${formatNumber(currentInput)} =`;
        currentInput = String(result);
        operator = null;
        previousInput = "";
        shouldResetInput = true;
        updateDisplay();
      }

      function clearAll() {
        currentInput = "0";
        previousInput = "";
        operator = null;
        shouldResetInput = false;
        expressionEl.textContent = "";
        updateDisplay();
      }

      function toggleSign() {
        if (currentInput !== "0" && currentInput !== "오류") {
          if (currentInput.startsWith("-")) {
            currentInput = currentInput.substring(1);
          } else {
            currentInput = "-" + currentInput;
          }
          updateDisplay();
        }
      }

      function percent() {
        if (currentInput !== "오류") {
          currentInput = String(parseFloat(currentInput) / 100);
          updateDisplay();
        }
      }

      function formatNumber(num) {
        const n = parseFloat(num);
        if (isNaN(n)) return num;
        return num;
      }

      // 키보드 지원
      document.addEventListener("keydown", (e) => {
        if (e.key >= "0" && e.key <= "9") appendNumber(e.key);
        else if (e.key === ".") appendDot();
        else if (e.key === "+") setOperator("+");
        else if (e.key === "-") setOperator("−");
        else if (e.key === "*") setOperator("×");
        else if (e.key === "/") {
          e.preventDefault();
          setOperator("÷");
        } else if (e.key === "Enter" || e.key === "=") calculate();
        else if (e.key === "Escape") clearAll();
        else if (e.key === "Backspace") {
          if (currentInput.length > 1) {
            currentInput = currentInput.slice(0, -1);
          } else {
            currentInput = "0";
          }
          updateDisplay();
        } else if (e.key === "%") percent();
      });
    </script>
  </body>
</html>

