    <style>
      * {
        margin: 0;
        padding: 0;
        box-sizing: border-box;
      }

      body {
        display: flex;
        justify-content: center;
        align-items: center;
        min-height: 100vh;
        background: linear-gradient(135deg, #1a1a2e, #16213e, #0f3460);
        font-family: "Segoe UI", Tahoma, Geneva, Verdana, sans-serif;
      }

      .calculator {
        background: rgba(255, 255, 255, 0.05);
        backdrop-filter: blur(20px);
        border-radius: 20px;
        padding: 24px;
        box-shadow: 0 25px 60px rgba(0, 0, 0, 0.5);
        border: 1px solid rgba(255, 255, 255, 0.1);
        width: 480px;
      }

      .mode-toggle {
        display: flex;
        gap: 8px;
        margin-bottom: 16px;
      }

      .mode-toggle button {
        flex: 1;
        padding: 8px;
        font-size: 13px;
        border: none;
        border-radius: 10px;
        cursor: pointer;
        background: rgba(255, 255, 255, 0.06);
        color: rgba(255, 255, 255, 0.5);
        transition: all 0.2s ease;
      }

      .mode-toggle button.active {
        background: rgba(99, 102, 241, 0.4);
        color: #a5b4fc;
      }

      .mode-toggle button:hover {
        background: rgba(255, 255, 255, 0.12);
      }

      .display {
        background: rgba(0, 0, 0, 0.3);
        border-radius: 14px;
        padding: 20px 24px;
        margin-bottom: 20px;
        text-align: right;
        border: 1px solid rgba(255, 255, 255, 0.05);
      }

      .display .expression {
        color: rgba(255, 255, 255, 0.5);
        font-size: 15px;
        min-height: 22px;
        word-break: break-all;
        line-height: 1.4;
      }

      .display .result {
        color: #fff;
        font-size: 38px;
        font-weight: 300;
        margin-top: 8px;
        overflow: hidden;
        text-overflow: ellipsis;
        white-space: nowrap;
      }

      .buttons {
        display: grid;
        grid-template-columns: repeat(5, 1fr);
        gap: 10px;
      }

      .buttons.basic-mode {
        grid-template-columns: repeat(4, 1fr);
      }

      button {
        padding: 16px 8px;
        font-size: 17px;
        border: none;
        border-radius: 12px;
        cursor: pointer;
        transition: all 0.2s ease;
        font-weight: 500;
